det_check_template:
proof fn det_new<T, Pred: Predicate<T>>(val: T, pred: Pred, r1: InvCell<T, Pred>, r2: InvCell<T, Pred>)
    requires (pred.predicate(val)),
    ensures
        ({
            &&& (r1.predicate() == pred)
            &&& (r2.predicate() == pred)
        }) ==> det_new_equal::<T, Pred>(r1, r2),
{
    reveal(InvCell::predicate);
{ASSUMES}}

equal_fn_def:
// Generated equal-fn for determinism check.
// Policy: errs_equivalent=True, opaque_ok=False
spec fn det_new_equal<T, Pred: Predicate<T>>(r1: InvCell<T, Pred>, r2: InvCell<T, Pred>) -> bool {
    (r1 == r2)
}
